from dataclasses import dataclass
from datetime import date
from statistics import mean

@dataclass
class TeamCostReport:
    team: str
    period: str
    budget_usd: float
    actual_spend_usd: float
    prior_period_spend_usd: float
    spend_by_feature: dict[str, float]
    unit_metrics: dict[str, float]    # cost_per_conv, llm_ratio, etc.
    open_actions: list[CostReviewActionItem]
    completed_actions_this_period: list[CostReviewActionItem]
    alerts: list[str]

    @property
    def budget_variance_usd(self) -> float:
        return self.actual_spend_usd - self.budget_usd

    @property
    def mom_change_pct(self) -> float:
        if self.prior_period_spend_usd == 0:
            return 0.0
        return (self.actual_spend_usd - self.prior_period_spend_usd) / self.prior_period_spend_usd

    def render_summary(self) -> str:
        lines = [
            f"=== {self.team} FinOps Review — {self.period} ===",
            "",
            f"  Spend:    ${self.actual_spend_usd:,.0f} / ${self.budget_usd:,.0f} budget "
            f"({self.actual_spend_usd/self.budget_usd:.0%})",
            f"  MoM:      {self.mom_change_pct:+.1%}",
            "",
            "  By feature:",
        ]
        for feat, cost in sorted(self.spend_by_feature.items(), key=lambda x: -x[1]):
            lines.append(f"    {feat:<30} ${cost:>8,.0f}")

        if self.alerts:
            lines += ["", "  Alerts:"]
            for a in self.alerts:
                lines.append(f"    ⚠ {a}")

        if self.open_actions:
            lines += ["", f"  Open actions ({len(self.open_actions)}):"]
            for a in self.open_actions:
                overdue = " [OVERDUE]" if a.is_overdue else ""
                lines.append(f"    [{a.status.value.upper()}]{overdue} {a.title} — {a.owner} (due {a.due_date})")

        return "\n".join(lines)
